import { useState } from "react";
import Sidebar from "./Sidebar";
import "./styles.css";

export default function App() {
    const [chats, setChats] = useState([
        { id: 1, title: "First Chat" },
        { id: 2, title: "React Help" },
        { id: 3, title: "AI Project" }
    ]);

    const [activeChatId, setActiveChatId] = useState(1);
    const [sidebarCollapsed, setSidebarCollapsed] = useState(false);

    const newChat = () => {
        const id = Date.now();
        setChats([{ id, title: "New Chat" }, ...chats]);
        setActiveChatId(id);
    };

    const renameChat = (id, title) => {
        if (!title) return;
        setChats(chats.map(c => c.id === id ? { ...c, title } : c));
    };

    const deleteChat = (id) => {
        setChats(chats.filter(c => c.id !== id));
        if (id === activeChatId && chats.length > 1) {
            setActiveChatId(chats[0].id);
        }
    };

    return (
        <div className={`app ${sidebarCollapsed ? "sidebar-collapsed" : ""}`}>
            <Sidebar
                chats={chats}
                activeChatId={activeChatId}
                onNewChat={newChat}
                onSelectChat={setActiveChatId}
                onRenameChat={renameChat}
                onDeleteChat={deleteChat}
                collapsed={sidebarCollapsed}
                toggleCollapsed={() => setSidebarCollapsed(v => !v)}
            />

            <main className="chat-area">
                <h1>Chat Area</h1>
                <p>Active chat ID: {activeChatId}</p>
            </main>
        </div>
    );
}
